1: import { render } from "ink";
2: import { createElement } from "react";
3: import { App } from "./tui/app.js";
4: import { runAgent } from "./agent.js";
5: import { Session } from "./session.js";
6: import { setActiveModel } from "./llm/index.js";
7: 
8: const args = process.argv.slice(2);
9: 
10: if (args.includes("--help") || args.includes("-h")) {
11:   console.log(`
12: TinyCode — Lightweight AI Coding Agent
13: 
14: Usage:
15:   tinycode [prompt]             One-shot mode: run prompt and print result
16:   tinycode                      Interactive mode: launch TUI
17: 
18: Options:
19:   --model <name>   Set the model variant (e.g., --model gemini-2.0-flash)
20:   --help, -h       Show this help message
21: `);
22:   process.exit(0);
23: }
24: 
25: const modelIndex = args.indexOf("--model");
26: if (modelIndex !== -1 && modelIndex + 1 < args.length) {
27:   try {
28:     setActiveModel(args[modelIndex + 1]);
29:   } catch (e) {
30:     console.error(`Error: ${(e as Error).message}`);
31:     process.exit(1);
32:   }
33:   args.splice(modelIndex, 2);
34: }
35: 
36: const prompt = args.find((a) => !a.startsWith("-"));
37: 
38: if (prompt) {
39:   await runOneShot(prompt);
40: } else {
41:   await runInteractive();
42: }
43: 
44: async function runOneShot(prompt: string): Promise<void> {
45:   const session = new Session();
46:   try {
47:     const result = await runAgent(prompt, session);
48:     console.log(result.text);
49:     process.exit(0);
50:   } catch (e) {
51:     const msg = e instanceof Error ? e.message : String(e);
52:     console.error(msg);
53:     process.exit(1);
54:   }
55: }
56: 
57: async function runInteractive(): Promise<void> {
58:   const { waitUntilExit } = render(createElement(App), { alternateScreen: true });
59:   await waitUntilExit();
60: }
